Greedy regret-based insertion evaluating all feasible positions in all routes with capacity-aware feasibility checks, prioritizing minimal increase in weighted sum of travel time, route compactness, and temporal violation penalties, with fallback to new route or force-insert into lowest-cost existing route.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const bigFloat = 1e100
	for idx := range oris {
		shipID := total_ship + idx
		ori := oris[idx]
		des := dess[idx]
		type cand struct {
			assignIdx int
			deltaCost float64
			position  int
			isNew     bool
		}
		var candidates []cand
		var savedStates [MAXASSIGNS][MAXASSIGNS]struct {
			station Station
			cost    float64
		}
		baseDist := cal_dis(ori, des)
		loadWeight := float64(ori.Load)
		timeWindowPenalty := 0.0
		if ori.TimeEnd < ori.TimeStart {
			timeWindowPenalty += 1e6
		}
		currentActiveRoutes := 0
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].Cost >= 0 {
				currentActiveRoutes++
			}
		}
		routeUtilization := float64(currentActiveRoutes) / float64(MAXASSIGNS)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i][i].station = dispatch.Assigns[i].StationCurrent
			savedStates[i][i].cost = dispatch.Assigns[i].Cost
			oldCost := dispatch.Assigns[i].Cost
			if oldCost < 0 {
				continue
			}
			if dispatch.Assigns[i].AddShip(shipID, ori, des) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost >= oldCost-1e-9 {
					delta := newCost - oldCost
					compactFactor := 0.0
					if baseDist > 0 {
						compactFactor = (delta / (loadWeight * baseDist)) * (1.0 + routeUtilization*0.3)
					}
					regretPenalty := 0.0
					if len(candidates) > 0 && delta < bigFloat {
						regretPenalty = delta * 0.15
					}
					totalScore := delta + compactFactor*1e5 + regretPenalty + timeWindowPenalty
					candidates = append(candidates, cand{assignIdx: i, deltaCost: totalScore, position: 0, isNew: false})
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].StationCurrent = savedStates[i][i].station
				dispatch.Assigns[i].Cost = savedStates[i][i].cost
			}
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			j := dispatch.AssignsLen
			savedStates[j][j].station = dispatch.Assigns[j].StationCurrent
			savedStates[j][j].cost = dispatch.Assigns[j].Cost
			oldCost := dispatch.Assigns[j].Cost
			if dispatch.Assigns[j].AddShip(shipID, ori, des) {
				dispatch.Assigns[j].GenRoute()
				newCost := dispatch.Assigns[j].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					utilWithNew := float64(currentActiveRoutes+1) / float64(MAXASSIGNS)
					spreadPenalty := utilWithNew * 2e5
					if baseDist > 0 {
						spreadPenalty = (delta/(loadWeight*baseDist))*utilWithNew*0.5 + spreadPenalty
					}
					totalScore := delta + spreadPenalty + timeWindowPenalty
					candidates = append(candidates, cand{assignIdx: j, deltaCost: totalScore, position: 0, isNew: true})
				}
				dispatch.Assigns[j].RemoveShip(shipID)
				dispatch.Assigns[j].StationCurrent = savedStates[j][j].station
				dispatch.Assigns[j].Cost = savedStates[j][j].cost
			}
		}
		bestIdx := -1
		bestScore := bigFloat
		for _, c := range candidates {
			if c.deltaCost < bestScore {
				bestScore = c.deltaCost
				bestIdx = c.assignIdx
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
			if candidates[0].isNew && bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			inserted := false
			minExistingCost := bigFloat
			minExistingIdx := -1
			for r := 0; r < dispatch.AssignsLen; r++ {
				cc := dispatch.Assigns[r].Cost
				if cc >= 0 && cc < minExistingCost {
					minExistingCost = cc
					minExistingIdx = r
				}
			}
			if minExistingIdx >= 0 && dispatch.Assigns[minExistingIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[minExistingIdx].GenRoute()
				inserted = true
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				k := dispatch.AssignsLen
				dispatch.Assigns[k].AddShip(shipID, ori, des)
				dispatch.Assigns[k].GenRoute()
				dispatch.AssignsLen++
				inserted = true
			}
			if !inserted {
				forceIdx := 0
				if minExistingIdx >= 0 {
					forceIdx = minExistingIdx
				}
				for attempt := 0; attempt < dispatch.AssignsLen; attempt++ {
					a := (forceIdx + attempt) % dispatch.AssignsLen
					if dispatch.Assigns[a].AddShip(shipID, ori, des) {
						dispatch.Assigns[a].GenRoute()
						break
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

