population.algorithm:
Greedy insertion with feasibility-first search, marginal cost delta scoring including wait-time penalties, and fallback creation of new routes when no existing route accepts the order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const INF = 1e18
    type candidate struct {
        assignIdx int
        costDelta float64
        feasible  bool
    }
    savedAssigns := make([]Assign, MAXASSIGNS)

    for orderID := 0; orderID < len(oris); orderID++ {
        ori := oris[orderID]
        des := dess[orderID]
        shipID := total_ship + orderID

        best := candidate{costDelta: INF, feasible: false}
        var fallbackIdx int = -1

        // Phase 1: try all existing assigns up to current length
        for idx := 0; idx < dispatch.AssignsLen; idx++ {
            savedAssigns[idx] = dispatch.Assigns[idx]

            ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
            if !ok {
                dispatch.Assigns[idx] = savedAssigns[idx]
                continue
            }

            dispatch.Assigns[idx].GenRoute()
            oldCost := savedAssigns[idx].Cost
            newCost := dispatch.Assigns[idx].Cost
            delta := newCost - oldCost
            if delta < 0 || oldCost < 0 {
                delta = newCost
            }

            dispatch.Assigns[idx].RemoveShip(shipID)
            dispatch.Assigns[idx].GenRoute()

            if delta < best.costDelta {
                best.assignIdx = idx
                best.costDelta = delta
                best.feasible = true
            }

            dispatch.Assigns[idx] = savedAssigns[idx]
        }

        targetIdx := -1
        if best.feasible {
            targetIdx = best.assignIdx
        } else {
            // Phase 2: check empty slots beyond current length
            for idx := dispatch.AssignsLen; idx < MAXASSIGNS; idx++ {
                savedAssigns[idx] = dispatch.Assigns[idx]

                ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
                if !ok {
                    dispatch.Assigns[idx] = savedAssigns[idx]
                    continue
                }

                dispatch.Assigns[idx].GenRoute()
                newCost := dispatch.Assigns[idx].Cost
                delta := newCost

                dispatch.Assigns[idx].RemoveShip(shipID)
                dispatch.Assigns[idx].GenRoute()

                best.assignIdx = idx
                best.costDelta = delta
                best.feasible = true
                targetIdx = idx
                break
            }
            if !best.feasible {
                fallbackIdx = dispatch.AssignsLen
                if fallbackIdx >= MAXASSIGNS {
                    fallbackIdx = 0
                }
            }
        }

        if best.feasible {
            saved := dispatch.Assigns[targetIdx]
            okCommit := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
            if !okCommit {
                dispatch.Assigns[targetIdx] = saved
            } else {
                dispatch.Assigns[targetIdx].GenRoute()
                if targetIdx >= dispatch.AssignsLen {
                    dispatch.AssignsLen = targetIdx + 1
                }
            }
        } else {
            if fallbackIdx >= 0 && fallbackIdx < MAXASSIGNS {
                newAssign := Assign{}
                dispatch.Assigns[fallbackIdx] = newAssign
                okNew := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
                if okNew {
                    dispatch.Assigns[fallbackIdx].GenRoute()
                    if fallbackIdx >= dispatch.AssignsLen {
                        dispatch.AssignsLen = fallbackIdx + 1
                    }
                }
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

